const body = $input.first().json.body || $input.first().json;
const transcript = body.transcript || '';
const callType = body.call_type || 'demo';

if (!transcript) {
  throw new Error('No transcript provided in request body');
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
  qs: { key: $vars.GEMINI_API_KEY },
  headers: { 'Content-Type': 'application/json' },
  body: {
    contents: [{
      parts: [{
        text: `You are a configuration assistant for Clara Answers.\nExtract ONLY explicitly stated facts. Never invent missing info.\nReturn ONLY valid JSON. No markdown. No explanation.\n\nUse this structure:\n{\n  "company_name": null,\n  "business_hours": {"days": null, "start": null, "end": null, "timezone": null},\n  "office_address": null,\n  "services_supported": [],\n  "emergency_definition": [],\n  "emergency_routing_rules": {"primary_contact": null, "phone_number": null, "fallback": null},\n  "non_emergency_routing_rules": {"action": null, "details": null},\n  "call_transfer_rules": {"timeout_seconds": null, "fail_message": null},\n  "special_clients": [],\n  "pricing": {"service_call_fee": null, "hourly_rate": null, "mention_to_caller": null},\n  "notification_preferences": {"email": null, "phone": null},\n  "integration_constraints": [],\n  "after_hours_flow_summary": null,\n  "office_hours_flow_summary": null,\n  "questions_or_unknowns": [],\n  "notes": null\n}\n\nTRANSCRIPT:\n${transcript}`
      }]
    }]
  },
  json: true
});

let raw = response.candidates?.[0]?.content?.parts?.[0]?.text?.trim();
if (!raw) throw new Error('Empty response from Gemini API');
raw = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '');

let memo;
try { memo = JSON.parse(raw); }
catch (err) { throw new Error('Failed to parse Gemini JSON: ' + raw); }

const slug = (memo.company_name || 'unknown').toLowerCase().replace(/[^a-z0-9]/g, '-').slice(0, 24);
memo.account_id = slug + '-' + Date.now().toString(16).slice(-4);
memo._meta = { extracted_at: new Date().toISOString(), call_type: callType, version: 'v1' };

return [{ json: { memo, transcript, call_type: callType } }];

const { memo } = $input.first().json;

const company = memo.company_name || 'our company';
const bh = memo.business_hours || {};
const days = bh.days || 'Monday to Friday';
const start = bh.start || '9:00 AM';
const end = bh.end || '5:00 PM';
const tz = bh.timezone || 'local time';
const routing = memo.emergency_routing_rules || {};
const phone = routing.phone_number || '[ON_CALL_NUMBER]';
const contact = routing.primary_contact || 'on-call team';
const timeout = (memo.call_transfer_rules || {}).timeout_seconds || 60;
const pricing = memo.pricing || {};

let pricingSection = '';
if (pricing.service_call_fee) {
  pricingSection = `\n# PRICING (only mention if caller asks)\n- Service call fee: ${pricing.service_call_fee}\n- Hourly rate: ${pricing.hourly_rate}\n- Do NOT mention on every call.`;
}

const systemPrompt = `# IDENTITY\nYou are Clara, AI voice assistant for ${company}.\nNever say you are an AI unless asked.\nKeep responses short — this is a phone call.\n\n# BUSINESS HOURS\n${days}, ${start} to ${end} ${tz}\n${pricingSection}\n\n---\n\n# BUSINESS HOURS FLOW\nStep 1 - Greeting: "Thank you for calling ${company}, this is Clara. How can I help?"\nStep 2 - Understand purpose: emergency, service request, or inquiry?\nStep 3 - Collect name and phone number. Repeat number back to confirm.\nStep 4 - Transfer to ${contact} at ${phone}. Wait ${timeout} seconds.\nStep 5 - If transfer fails: "I couldn't reach someone right now. Your info is noted and someone will call you back shortly."\nStep 6 - "Is there anything else?" → "Thank you for calling ${company}. Have a great day!"\n\n---\n\n# AFTER HOURS FLOW\nStep 1 - "Thank you for calling ${company}. Office is closed. This is Clara, how can I help?"\nStep 2 - Determine if emergency or non-emergency.\nStep 3a - IF EMERGENCY: collect name, phone, address → transfer to ${phone}\n         If fails: "Your call is flagged urgent. Someone calls you back very shortly."\nStep 3b - IF NOT EMERGENCY: collect details → "We will follow up next business day."\nStep 4 - "Is there anything else?" → "Thank you. Have a good night!"\n\n---\n\n# RULES\n- Never ask more than 2 questions at once\n- Never mention tools, functions or systems\n- Always repeat phone numbers back to confirm\n- Be warm and calm always`;

const spec = {
  agent_name: `Clara - ${company}`,
  version: memo._meta?.version || 'v1',
  voice_style: { tone: 'warm, professional, calm', pace: 'natural, not rushed' },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: company,
    timezone: bh.timezone,
    business_days: bh.days,
    emergency_phone: phone,
    transfer_timeout_seconds: timeout
  },
  call_transfer_protocol: { method: 'warm_transfer', timeout_seconds: timeout, announcement: 'Please hold while I connect you.' },
  fallback_protocol: { trigger: 'Transfer fails', message: "I'm sorry I couldn't reach someone. Your info is recorded and someone will follow up soon." },
  questions_or_unknowns: memo.questions_or_unknowns || [],
  _meta: { generated_at: new Date().toISOString(), account_id: memo.account_id }
};

return [{ json: { memo, spec } }];

const { memo, spec } = $input.first().json;

const RETELL_API_KEY = $vars.RETELL_API_KEY;

if (!RETELL_API_KEY) {
  throw new Error('RETELL_API_KEY not set in n8n environment variables');
}

const headers = {
  'Authorization': `Bearer ${RETELL_API_KEY}`,
  'Content-Type': 'application/json'
};

// Step 1 — Create LLM
const llmResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.retellai.com/create-retell-llm',
  headers,
  body: {
    model: 'claude-4.5-sonnet',
    system_prompt: spec.system_prompt,
    temperature: 0,
    max_tokens: 200
  },
  json: true
});

const llmId = llmResponse.llm_id;
if (!llmId) throw new Error('LLM creation failed: ' + JSON.stringify(llmResponse));

// Step 2 — Create Agent
const company = memo.company_name || 'the business';
const agentResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.retellai.com/create-agent',
  headers,
  body: {
    agent_name: `Clara - ${company}`,
    response_engine: {
      type: 'retell-llm',
      llm_id: llmId
    },
    voice_id: '11labs-Adrian',
    language: 'en-US',
    begin_message: `Thank you for calling ${company}, this is Clara. How can I help you today?`
  },
  json: true
});

const agentId = agentResponse.agent_id;
if (!agentId) throw new Error('Agent creation failed: ' + JSON.stringify(agentResponse));

const retellResult = {
  success: true,
  agent_id: agentId,
  llm_id: llmId,
  retell_url: `https://app.retellai.com/agent/${agentId}`
};

return [{ json: { memo, spec, retell: retellResult } }];

